###################################################################### Program   : Fuclone 1.1                                           ## Purpose   : Clones Fusions database tables to Local database.     ## Built by  : RAM CH                                                ## Changed on: 10/10/19 added support for Proxy,12c+, metadata issue ## Changed on: 15/11/18 Version 1.0 release                          ## Changed on: 14/11/18 (setup_views() added to create all views)    ## Changed on: 07/11/18 (setup_tables() added to create all tables)  ## Created on: 01/11/18 (Initial Beta Release)                       ## Python    : 3.5.4                                                 ######################################################################import argparseimport base64import configparserimport loggingimport osimport reimport timefrom argparse import RawTextHelpFormatterfrom itertools import isliceimport cx_Oracleimport untanglefrom suds import WebFaultfrom suds.client import Clientfrom suds.plugin import MessagePlugindef get_logger(level='INFO'):    """Setups 2 loggers, one for Error messages to screen and another one for detail log to file. Sets file log level to    parameter passed. If nothing passed then log level is set to Warning.    Usage: --log=debug or --log=DEBUG"""    log_file='fuclonelog_'+time.strftime("%Y%m%d%H%m%S")+'.txt'    try:        for handler in logging.root.handlers[:]:            logging.root.removeHandler(handler)        lognum = getattr(logging, level.upper(), None)        if not isinstance(lognum, int):            # lognum = logging.INFO            lognum = logging.DEBUG            # print("Invalid or No log level specified. Running with log level 'Warning'.".format(level))        logging.basicConfig(level=lognum, format="%(asctime)s [%(levelname)-5.5s]  %(message)s",                            # datefmt='%m-%d %H:%M', filename='fuclone.log'                            filename=log_file,filemode='w')        logging.getLogger('suds').setLevel(logging.CRITICAL)        # define a Handler which writes Error messages or higher to the sys.stderr        console = logging.StreamHandler()        console.setLevel(logging.INFO)        console.setFormatter(logging.Formatter(' %(levelname)-8s: %(message)s'))        # add the handler to the root logger        logging.getLogger('').addHandler(console)        logging.info('\n#######################################\n##             FUCLONE 1.1           ##\n#######################################');        logging.info('Log File: {0}'.format(log_file))        logging.debug('Logger initiated.')        return logging    except Exception as e:        print('Fail to initiate Logger. Terminating Fuclone Application: {0}'.format(e))        os._exit(1)def get_config(env_name=''):    """Loads Fusion environment details from fuclone.ini file to clone.    Usage: get_config(env_name)    If no environment name is passed, then 1st environment details are used for processing."""    env = ''    app_conf = {}    fuclone_sec = 'FUCLONE'    config = configparser.ConfigParser()    try:        config.read('fuclone.ini')        if len(config._sections) < 2:            raise Exception('fuclone.ini file must have at least 2 sections including the mandatory 1st section FUCLONE.')        if not config._sections.get(fuclone_sec):            raise Exception('Section {0} Not found in fuclone.ini file. Terminating application.'.format(fuclone_sec))        app_conf[fuclone_sec] = dict(config._sections.get(fuclone_sec))        # if env is not passed then pick the 2nd section        if not env_name:            env = list(config._sections.keys())[1]        else:            env = env_name.upper()        if not config._sections.get(env):            raise Exception('Section {0} Not found in fuclone.ini file. Terminating application.'.format(env))        app_conf[env] = dict(config._sections.get(env))        return (app_conf)    except FileNotFoundError:        logger.error("fuclone.ini file not found. Terminating application.")        os._exit(1)    except Exception as e:        logger.error(e)        os._exit(1)class DeleteEmptyTags(MessagePlugin):    """Removes empty tags before sending request to BIP"""    def clear_empty_tags(self, tags):        for tag in tags:            children = tag.getChildren()[:]            if children:                self.clear_empty_tags(children)            if re.match(r'^<[^>]+?/>$', tag.plain()):                tag.parent.remove(tag)    def marshalled(self, context):        self.clear_empty_tags(context.envelope.getChildren()[:])def setup_clonedb(config):    """Setup Clone DB by creating apps schema and FND_Tables. Takes configuration as input and Returns True if process completes else False.    Usage: setup_clone(config) config is dictionary type."""    result = False    logger.info('Clone database setup process started.')    try:        user = config['FUCLONE'].get('user').upper()        password = config['FUCLONE'].get('password')        con_str = config['FUCLONE'].get('db_con')        sys_password = config['FUCLONE'].get('sys_password')        dba_con = cx_Oracle.connect('sys', sys_password, con_str, mode=cx_Oracle.SYSDBA)        if not dba_con:            raise Exception('Fail to connect as sysdba.')        dba_run = dba_con.cursor().execute        logger.debug('DBA Connection established.')        # 12c and above support        dba_run('alter session set "_ORACLE_SCRIPT"=true')        # Create apps tablespace. if exists, then ask users to overwrite or exit. For now just drop.        qry_result = dba_run("SELECT tablespace_name FROM dba_tablespaces where tablespace_name='{0}'".format(user)).fetchall()        if qry_result:            dba_run('DROP TABLESPACE {0} INCLUDING CONTENTS AND DATAFILES'.format(user))            logger.debug('Tablespace {0} dropped.'.format(user))        dba_run("CREATE TABLESPACE {0} DATAFILE '{0}_db.dat' SIZE 2 G REUSE AUTOEXTEND ON NEXT 2 G MAXSIZE UNLIMITED nologging".format(user))        logger.debug('Tablespace {0} created.'.format(user))        # Create user. Disconnect & Drop if already exists.        qry_result = dba_run("SELECT USERNAME FROM ALL_USERS WHERE USERNAME='{0}'".format(user)).fetchall()        if qry_result:            # Look for active user sessions            usr_ses = dba_run("SELECT SID||','|| SERIAL# AS SID FROM V$SESSION WHERE USERNAME ='{0}'".format(user)).fetchall()            while usr_ses:                # Kill user sessions                logger.debug('Killing active session {0} for user {1}.'.format(usr_ses[0][0], user))                dba_run("ALTER SYSTEM KILL SESSION '{0}'".format(usr_ses[0][0]))                del usr_ses[0]            time.sleep(5)            dba_run("DROP USER {0} CASCADE".format(user))            logger.debug('User {0} dropped.'.format(user))        qry_result = dba_run("SELECT to_number(SUBSTR(version,0,2)) FROM PRODUCT_COMPONENT_VERSION where ROWNUM=1").fetchall()        # if db_version<12:        dba_run('CREATE USER {0} IDENTIFIED BY {1} DEFAULT TABLESPACE {0} TEMPORARY TABLESPACE "TEMP"'.format(user, password))        # else:        #     dba_run('CREATE USER {0} IDENTIFIED BY {1} CONTAINER=all DEFAULT TABLESPACE {0} TEMPORARY TABLESPACE "TEMP"'.format(user, password))        logger.debug('{0} user created.'.format(user))        dba_run("GRANT CONNECT, RESOURCE, DBA TO {0}".format(user))        logger.debug('DBA Grants given to user {0}.'.format(user))        # Close DBA Connection as no more needed        dba_con.commit()        dba_con.close()        logger.info('Clone DB table space and user creation completed.')        result = setup_metadata(config)        if result:            logger.info('Fuclone Setup process complete.')        else:            raise Exception()    except (WebFault, cx_Oracle.DatabaseError) as e:        error, = e.args        logger.error('Clone DB setup failed: {0}'.format(error.message))    except Exception as e:        if e:            logger.error('Clone DB setup failed: {0}'.format(e))    finally:        return resultdef setup_metadata(config):    """Create and load Metadata tables (FND) from Fusion cloud    Usage: setup_metadata(config) """    result = False    table_list = ['FND_TABLES', 'FND_COLUMNS', 'FND_VIEWS']    # table_list = ['FND_TABLES','FND_COLUMNS']    # table_list = ['FND_SOURCE']    logger.info('Meta data creation started.')    try:        # Create FUCLONE on Fusion cloud        cloud_db = Bip(config)        if not cloud_db.session:            raise Exception()        if not cloud_db.create_folder():            raise Exception()        if not cloud_db.create_report():            raise Exception()        cloud_db.__close__()        logger.info('Metadata creation on Cloud complete and Clone database started.')        if clone(config, table_list):            result = True        else:            raise Exception()    except (WebFault, cx_Oracle.DatabaseError) as e:        logger.error('Metadata setup failed: {0}'.format(e.fault.faultstring))    except Exception as e:        if e:            logger.error('Metadata setup failed: {0}'.format(e))    finally:        return resultdef setup_tables(config, object_list=[]):    """Creates missing tables from FND tables    Usage: setup_tables(config, table_list) """    result = False    pass_count = 0    fail_list = []    object_type = 'Tables'    try:        clone_db = Database(config)        if not clone_db.db_con:            raise Exception()        if not object_list:            object_list = clone_db.run(                "SELECT DISTINCT FT.TABLE_NAME FROM FND_TABLES FT JOIN FND_COLUMNS FC ON FT.TABLE_ID = FC.TABLE_ID AND FC.COLUMN_NAME NOT LIKE 'EXTN_ATTRIBUTE%' AND FC.STATUS='Active' AND "                "FC.COLUMN_TYPE IN('CHAR','D','N','TIMESTAMP','TIMESTAMP_WITH_TIMEZONE','V') WHERE TABLE_NAME NOT IN (SELECT TNAME FROM TAB WHERE TABTYPE='TABLE') ORDER BY 1").fetchall()            object_list = [obj[0] for obj in object_list]        elif '%' in object_list[0]:            object_list = clone_db.run("SELECT DISTINCT FT.TABLE_NAME FROM FND_TABLES FT JOIN FND_COLUMNS FC ON FT.TABLE_ID = FC.TABLE_ID AND FC.COLUMN_NAME NOT LIKE 'EXTN_ATTRIBUTE%' AND FC.STATUS='Active' AND FC.COLUMN_TYPE IN('CHAR','D','N','TIMESTAMP','TIMESTAMP_WITH_TIMEZONE','V') WHERE TABLE_NAME LIKE '{0}' AND TABLE_NAME NOT IN (SELECT TNAME FROM TAB WHERE TABTYPE='TABLE') ORDER BY 1".format(object_list[0])).fetchall()            object_list = [obj[0] for obj in object_list]        logger.info('{0} to create ({1}):{2}'.format(object_type, len(object_list), ','.join(object_list)))        for obj in object_list:            if clone_db.create_table(obj, drop=False):                pass_count += 1            else:                fail_list.append(obj)            if pass_count and (pass_count % clone_db.commit_size == 0):                clone_db.db_con.commit()                logger.info('{0} to create {1}'.format(object_type, len(object_list) - pass_count - len(fail_list)))        if not fail_list:            result = True    except cx_Oracle.DatabaseError as e:        logger.error('Fail to process {0} list: {1}'.format(object_type, e.fault.faultstring))    except Exception as e:        if e:            logger.error(e)    finally:        logger.info('\n########################################\n##FUCLONE Setup {0} Process Summary##\n########################################\n\nTotal({1}), Success({2}), Fail({3})'.format(object_type, len(object_list), pass_count, len(fail_list)))        if fail_list:            logger.info('{0} Failed: {1}'.format(object_type, ', '.join(fail_list)))        return (result)def setup_views(config, object_list=[]):    """Creates missing tables from FND tables    Usage: setup_tables(config, table_list) """    result = False    pass_count = 0    fail_list = []    object_type = 'Views'    try:        clone_db = Database(config)        if not clone_db.db_con:            raise Exception()        if not object_list:            object_list = clone_db.run("SELECT VIEW_NAME,TEXT FROM FND_VIEWS WHERE VIEW_NAME NOT IN (SELECT VIEW_NAME FROM USER_VIEWS) ORDER BY VIEW_ID").fetchall()            object_list = [obj[0] for obj in object_list]        elif '%' in object_list[0]:            object_list = clone_db.run("SELECT VIEW_NAME,TEXT FROM FND_VIEWS WHERE VIEW_NAME LIKE '{0}' AND VIEW_NAME NOT IN (SELECT VIEW_NAME FROM USER_VIEWS) ORDER BY VIEW_ID".format(object_list[0])).fetchall()            object_list = [obj[0] for obj in object_list]        logger.info('{0} to create ({1}):{2}'.format(object_type, len(object_list), ','.join(object_list)))        for obj in object_list:            if clone_db.create_view(obj):                pass_count += 1            else:                fail_list.append(obj)            if pass_count and (pass_count % clone_db.commit_size == 0):                clone_db.db_con.commit()                logger.info('{0} to create {1}'.format(object_type, len(object_list) - pass_count - len(fail_list)))        if not fail_list:            result = True    except cx_Oracle.DatabaseError as e:        logger.error('Fail to process {0} list: {1}'.format(object_type, e.fault.faultstring))    except Exception as e:        if e:            logger.error(e)    finally:        logger.info('\n########################################\n##FUCLONE Setup {0} Process Summary##\n########################################\n\nTotal({1}), Success({2}), Fail({3})'.format(object_type, len(object_list), pass_count, len(fail_list)))        if fail_list:            logger.info('{0} Failed: {1}'.format(object_type, ', '.join(fail_list)))        return (result)def load_file_to_table(config, table, file):    result = False    row_count = 0    try:        logger.debug('Loading {0} from file {1} started.'.format(table, file))        input_file = open(file, 'r')        if not input_file.__sizeof__():            logger.error('{0} is empty.'.format(file))            raise Exception()        input_file.close()        clone_db = Database(config)        if not clone_db.db_con:            raise Exception()        if not clone_db.create_table(table):            raise Exception()        sql = clone_db.get_insert_sql(table)        if not sql:            raise Exception()        clone_db.db_con.cursor().execute("ALTER SESSION SET NLS_DATE_FORMAT = 'DD/MM/YYYY HH24:MI:SS'")        with open(file, 'r') as file_opened:            while (True):                data = [line.strip().split('|') for line in islice(file_opened, clone_db.batch_size)]                if not data:                    break                row_count += len(data)                clone_db.db_con.cursor().executemany(sql, data)                logger.debug('{0}: {1} rows loaded.'.format(table, row_count))        # self.db_con.cursor().executemany(sql, data)        clone_db.run("ALTER SESSION SET NLS_DATE_FORMAT = 'DD/MM/YY'")        clone_db.db_con.commit()        logger.info('{0}: Total {1} rows loaded.'.format(table, row_count))        result = True    except cx_Oracle.DatabaseError as e:        logger.error('{0}: Fail to load from file {1}: {2}'.format(table, file, e.fault.faultstring))    except FileNotFoundError:        logger.error("{0} not found.".format(file))    except Exception as e:        if e:            logger.error(e)    finally:        return resultclass Database:    """ Class having Oracle DB connection and methods to query data """    # Initialize class variables    sql = ''    user = ''    con_str = ''    password = ''    run = None    db_con = None    table_list = []    batch_size = 100000    commit_size = 500    meta_ext_tables = ['FND_VIEWS', 'FND_SOURCE']    def __init__(self, config):        self.user = config['FUCLONE'].get('user').upper()        self.password = config['FUCLONE'].get('password')        self.con_str = config['FUCLONE'].get('db_con')        # https: // ecsj.login.em2.oraclecloud.com        try:            # Open database connection            self.db_con = cx_Oracle.connect(self.user, self.password, self.con_str, encoding="UTF-8", nencoding="UTF-8")            self.run = self.db_con.cursor().execute            logger.debug('Clone DB Connection established')        except (WebFault, cx_Oracle.DatabaseError) as e:            error, = e.args            logger.error('Clone DB connection error, check ini file: {0}'.format(error.message))            self.db_con = None            # os._exit(1)        except Exception as e:            if e:                logger.error('Clone DB connection error, check ini file: {0}'.format(e))            self.db_con = None    def __close__(self):        try:            self.db_con.commit()            self.db_con.close()        except:            pass    def create_view(self, view):        """Create view using view definition from FND_VIEWS tables        Usage: create_view(view_name, sql, Boolean drop) """        result = False        try:            logger.debug('{0} view creation started'.format(view))            view_def = self.run("SELECT TEXT FROM FND_VIEWS WHERE VIEW_NAME ='{0}'".format(view)).fetchall()            for v in view_def:                sql = "CREATE OR REPLACE FORCE VIEW {0} AS {1}".format(view, str(v[0]).replace('\n', '\r\n'))            logger.debug('View DDL: {0}'.format(sql))            self.run(sql)            logger.debug('{0} views created'.format(view))            result = True        except cx_Oracle.DatabaseError as e:            error, = e.args            logger.error('{0}: Fail to create view: {1}'.format(view, error.message))        except Exception as e:            if e:                logger.error(e)        finally:            return result    def drop_table(self, table):        """Drops and purges a given table and commits to database..        Usage: drop_table(table)"""        result = False        try:            self.run("drop table {0} CASCADE CONSTRAINTS purge".format(table))            self.db_con.commit()            logger.debug(table + ' dropped.')            result = True        except (WebFault, cx_Oracle.DatabaseError) as e:            error, = e.args            if error.code == 942:                result = True                logger.debug('{0} table does not exists. Skipping drop.'.format(table))            else:                logger.error('{0}: Drop table failed: {1}'.format(table, error.message))        except Exception as e:            if e:                logger.error('{0}: Drop table failed: {1}'.format(table, e))        finally:            return result    def create_table(self, table, drop=True):        """Create table using table definition from FND_TABLES & FND_COLUMNS tables        Usage: create_table(table) Ex: create_table('PO_LINES_ALL')"""        result = False        try:            if drop:                # Drop the table before create. exit if fail to drop.                if not self.drop_table(table):                    raise Exception()            # Frame sql            if table == 'FND_TABLES':                create_sql = 'CREATE TABLE FND_TABLES( table_id NUMBER, table_name VARCHAR2(30), application_short_name VARCHAR2(50), user_table_name VARCHAR2(80), last_update_date DATE, last_updated_by VARCHAR2(64), creation_date DATE, created_by VARCHAR2(64), last_update_login VARCHAR2(32), table_type VARCHAR2(10), description VARCHAR2(4000), hosted_support_style VARCHAR2(30), logical VARCHAR2(1), mls_support_model VARCHAR2(30), status VARCHAR2(30), deploy_to VARCHAR2(30), extension_of_table VARCHAR2(30), short_name VARCHAR2(30), shared_object VARCHAR2(30), conflict_resolution VARCHAR2(30), tablespace_type VARCHAR2(30), select_allowed VARCHAR2(1), insert_allowed VARCHAR2(1), update_allowed VARCHAR2(1), delete_allowed VARCHAR2(1), truncate_allowed VARCHAR2(1), maintain_partition VARCHAR2(1), exchange_partition VARCHAR2(1), maintain_index VARCHAR2(1), flashback_allowed VARCHAR2(1), enable_audit VARCHAR2(1))'            elif table == 'FND_COLUMNS':                create_sql = 'CREATE TABLE FND_COLUMNS( table_id NUMBER, column_id NUMBER, column_name VARCHAR2(30), user_column_name VARCHAR2(80), column_sequence NUMBER, last_update_date DATE, last_updated_by VARCHAR2(64), creation_date DATE, created_by VARCHAR2(64), last_update_login VARCHAR2(32), column_type VARCHAR2(30), width NUMBER, null_allowed_flag VARCHAR2(1), translate_flag VARCHAR2(1), description VARCHAR2(4000), precision NUMBER, scale NUMBER, domain_code VARCHAR2(30), status VARCHAR2(30), denorm_path VARCHAR2(80), short_name VARCHAR2(30), routing_mode VARCHAR2(30), version_column VARCHAR2(30), eligible_to_be_secured VARCHAR2(1), security_classification VARCHAR2(30))'            elif table == 'FND_VIEWS':                create_sql = "CREATE TABLE FND_VIEWS( VIEW_ID NUMBER, VIEW_NAME VARCHAR2(30 BYTE), APPLICATION_SHORT_NAME VARCHAR2(50 BYTE), LAST_UPDATE_DATE DATE, LAST_UPDATED_BY VARCHAR2(64 BYTE), CREATION_DATE DATE, CREATED_BY VARCHAR2(64 BYTE), LAST_UPDATE_LOGIN VARCHAR2(32 BYTE), DESCRIPTION VARCHAR2(4000 BYTE), STATUS VARCHAR2(30 BYTE), SELECT_ALLOWED VARCHAR2(1 BYTE), INSERT_ALLOWED VARCHAR2(1 BYTE), UPDATE_ALLOWED VARCHAR2(1 BYTE), DELETE_ALLOWED VARCHAR2(1 BYTE), FLASHBACK_ALLOWED VARCHAR2(1 BYTE), TEXT CLOB)"            elif table == 'FND_INDEXES':                create_sql = 'CREATE TABLE FND_INDEXES( table_id NUMBER, index_id NUMBER, index_name VARCHAR2(30), last_update_date DATE, last_updated_by VARCHAR2(64), creation_date DATE, created_by VARCHAR2(64), last_update_login VARCHAR2(32), uniqueness VARCHAR2(1), deploy_to VARCHAR2(30), status VARCHAR2(30), short_name VARCHAR2(30))'            elif table == 'FND_SOURCE':                create_sql = 'CREATE TABLE FND_SOURCE( OWNER VARCHAR2(30 BYTE), NAME VARCHAR2(30 BYTE), TYPE VARCHAR2(12 BYTE), LINE NUMBER, TEXT VARCHAR2(4000 BYTE), ORIGIN_CON_ID NUMBER)'            else:                qry = """SELECT DECODE(ROWNUM,1,'',',') || EXT FROM( SELECT FC.COLUMN_NAME || ' ' || DECODE(COLUMN_TYPE,'D','Date','N','Number','TIMESTAMP','Date','TIMESTAMP_WITH_TIMEZONE','Date','V','Varchar2(' || WIDTH || ')',COLUMN_TYPE) EXT FROM FND_TABLES FT, FND_COLUMNS FC WHERE FT.TABLE_ID = FC.TABLE_ID AND FC.COLUMN_NAME NOT LIKE 'EXTN_ATTRIBUTE%' AND FC.STATUS = 'Active' AND FC.COLUMN_TYPE IN ( 'CHAR', 'D', 'N', 'TIMESTAMP', 'TIMESTAMP_WITH_TIMEZONE', 'V') AND FT.TABLE_NAME = '{0}' ORDER BY FC.COLUMN_SEQUENCE )""".format(table)                # logger.debug('Query issued to get columns for table{0}: {1}'.format(table,qry))                # Run above query to DB to get final select SQL                qry_result = self.run(qry).fetchall()                if qry_result:                    create_sql = 'CREATE TABLE {0} ('.format(table) + ' '.join([row[0] for row in qry_result]) + ')'                else:                    raise Exception('{0}: Fail to create table as definition not found in Metadata.'.format(table))            logger.debug('DDL for {0}: {1}'.format(table, create_sql))            self.run(create_sql)            # self.db_con.commit()            logger.debug('{0} created.'.format(table))            result = True        except (WebFault, cx_Oracle.DatabaseError) as e:            error, = e.args            logger.error('{0}: Fail to create table: {1}'.format(table, error.message))        except Exception as e:            if e:                logger.error(e)        finally:            return result    def get_tables(self):        """Loads table names from tables.txt file to clone."""        result = False        self.table_list = []        try:            logger.debug('Generating Tables list.')            input_file = open('tables.txt', 'r')            if input_file.__sizeof__():                for line in input_file.read().splitlines():                    # clean the input line and Check for wildcard % in table name from file                    line = line.strip().upper()                    # if line.find('%') and line.find(':'):                    #     raise Exception ('{0}: Invalid Table entry. Filter(:) and Wildcard(%) can not be used together.')                    if line.find('%') < 1:                        self.table_list.append(line)                    else:                        # Bring all table names from fnd_table matching wildcard pattern                        sub_list = self.run("SELECT DISTINCT FT.TABLE_NAME FROM FND_TABLES FT JOIN FND_COLUMNS FC ON FT.TABLE_ID = FC.TABLE_ID AND FC.COLUMN_NAME NOT LIKE 'EXTN_ATTRIBUTE%' AND FC.STATUS='Active' AND FC.COLUMN_TYPE IN('CHAR','D','N','TIMESTAMP','TIMESTAMP_WITH_TIMEZONE','V') WHERE TABLE_NAME LIKE '{0}' ORDER BY 1".format(line)).fetchall()                        if sub_list:                            self.table_list += [name[0] for name in sub_list]                        else:                            logger.warning('Pattern {1} not found in Metadata.'.format(line))                input_file.close()            else:                raise Exception("table.txt file is empty.")            result = True            logger.info('Tables to process ({0}): {1}'.format(len(self.table_list), ', '.join(self.table_list)))            # return (result)        except FileNotFoundError:            logger.error("table.txt file not found.")        except (WebFault, cx_Oracle.DatabaseError) as e:            logger.error('Table list generation failed: {0}'.format(e.args[1]))        except Exception as e:            if e:                logger.error('Table list generation failed: {0}'.format(e))        finally:            return result    def get_counts(self, table):        """Returns row count from table        Usage: get_counts(table)"""        result = False        try:            if table == 'FND_SOURCE':                sql = "SELECT COUNT(*) AS TABLE_EXTRACT FROM USER_SOURCE"            else:                sql = 'SELECT COUNT(*) AS TABLE_EXTRACT FROM {0}'.format(table)            result = self.run(sql).fetchall()[0][0]            logger.debug('{0}: {1} rows available on clone database.'.format(table, result))        except (Exception, WebFault, cx_Oracle.DatabaseError) as e:            error, = e.args            if not error:                pass            elif error.code == 942:                logger.debug('{0}: Row count failed as table missing in Metadata.'.format(table))                result = 0            else:                logger.error('{0}: Row count failed: {1}'.format(table, error.message))        # except Exception as e:        #     logger.error('{0}: Row count failed'.format(e))        finally:            return result    def get_sql(self, table):        """Generates Select SQL for any given table.        Usage: get_sql(table)"""        # Frame sql        self.sql = ''        if table == 'FND_TABLES':            self.sql = """SELECT regexp_replace(TABLE_ID,'[[:cntrl:]||]',' ') ||'|'|| regexp_replace(TABLE_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(APPLICATION_SHORT_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(USER_TABLE_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TO_CHAR(last_update_date, 'DD/MM/YYYY HH24:MI:SS'),'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LAST_UPDATED_BY,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TO_CHAR(creation_date, 'DD/MM/YYYY HH24:MI:SS'),'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(CREATED_BY,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LAST_UPDATE_LOGIN,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TABLE_TYPE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DESCRIPTION,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(HOSTED_SUPPORT_STYLE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LOGICAL,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(MLS_SUPPORT_MODEL,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(STATUS,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DEPLOY_TO,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(EXTENSION_OF_TABLE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SHORT_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SHARED_OBJECT,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(CONFLICT_RESOLUTION,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TABLESPACE_TYPE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SELECT_ALLOWED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(INSERT_ALLOWED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(UPDATE_ALLOWED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DELETE_ALLOWED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TRUNCATE_ALLOWED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(MAINTAIN_PARTITION,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(EXCHANGE_PARTITION,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(MAINTAIN_INDEX,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(FLASHBACK_ALLOWED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(ENABLE_AUDIT,'[[:cntrl:]||]',' ' ) AS TABLE_EXTRACT FROM FND_TABLES"""        elif table == 'FND_COLUMNS':            # Fixed metadata issues by getting data from oracle seed tables.            self.sql = """SELECT FC.TABLE_ID || '|' || FC.COLUMN_ID || '|' || REGEXP_REPLACE(FC.COLUMN_NAME, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.USER_COLUMN_NAME, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.COLUMN_SEQUENCE, '[[:cntrl:]||]', ' ') || '|' || TO_CHAR(FC.LAST_UPDATE_DATE, 'DD/MM/YYYY HH24:MI:SS') || '|' || REGEXP_REPLACE(FC.LAST_UPDATED_BY, '[[:cntrl:]||]', ' ') || '|' || TO_CHAR(FC.CREATION_DATE, 'DD/MM/YYYY HH24:MI:SS') || '|' || REGEXP_REPLACE(FC.CREATED_BY, '[[:cntrl:]||]', ' ') || '|' || FC.LAST_UPDATE_LOGIN || '|' || FC.COLUMN_TYPE || '|' || UC.DATA_LENGTH || '|' || FC.NULL_ALLOWED_FLAG || '|' || FC.TRANSLATE_FLAG || '|' || REGEXP_REPLACE(FC.DESCRIPTION, '[[:cntrl:]||]', ' ') || '|' || FC.PRECISION || '|' || FC.SCALE || '|' || REGEXP_REPLACE(FC.DOMAIN_CODE, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.STATUS, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.DENORM_PATH, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.SHORT_NAME, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.ROUTING_MODE, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.VERSION_COLUMN, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.ELIGIBLE_TO_BE_SECURED, '[[:cntrl:]||]', ' ') || '|' || REGEXP_REPLACE(FC.SECURITY_CLASSIFICATION, '[[:cntrl:]||]', ' ') AS TABLE_EXTRACT FROM FND_COLUMNS FC JOIN FND_TABLES FT ON FT.TABLE_ID = FC.TABLE_ID JOIN ALL_TAB_COLUMNS UC ON UC.TABLE_NAME = FT.TABLE_NAME AND UC.COLUMN_NAME = FC.USER_COLUMN_NAME AND UC.OWNER = 'FUSION'"""            # self.sql = """SELECT regexp_replace(TABLE_ID,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(COLUMN_ID,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(COLUMN_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(USER_COLUMN_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(COLUMN_SEQUENCE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TO_CHAR(last_update_date, 'DD/MM/YYYY HH24:MI:SS'),'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LAST_UPDATED_BY,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TO_CHAR(creation_date, 'DD/MM/YYYY HH24:MI:SS'),'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(CREATED_BY,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LAST_UPDATE_LOGIN,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(COLUMN_TYPE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(WIDTH,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(NULL_ALLOWED_FLAG,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TRANSLATE_FLAG,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DESCRIPTION,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(PRECISION,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SCALE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DOMAIN_CODE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(STATUS,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DENORM_PATH,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SHORT_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(ROUTING_MODE,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(VERSION_COLUMN,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(ELIGIBLE_TO_BE_SECURED,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SECURITY_CLASSIFICATION,'[[:cntrl:]||]',' ' )AS TABLE_EXTRACT  FROM FND_COLUMNS"""        # elif table == 'FND_VIEWS':        #     self.sql = "SELECT view_id AS view_id, view_name AS view_name, application_short_name AS application_short_name, TO_CHAR(last_update_date,'DD/MM/YYYY HH24:MI:SS') AS last_update_date, last_updated_by AS last_updated_by, TO_CHAR(creation_date,'DD/MM/YYYY HH24:MI:SS') AS creation_date, created_by AS created_by, last_update_login AS last_update_login, description AS description, text AS text, status AS status, select_allowed AS select_allowed, insert_allowed AS insert_allowed, update_allowed AS update_allowed, delete_allowed AS delete_allowed, flashback_allowed AS flashback_allowed FROM fnd_views"        # elif table == 'FND_INDEXES':        #     self.sql = """SELECT regexp_replace(TABLE_ID,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(INDEX_ID,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(INDEX_NAME,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TO_CHAR(last_update_date, 'DD/MM/YYYY HH24:MI:SS'),'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LAST_UPDATED_BY,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(TO_CHAR(creation_date, 'DD/MM/YYYY HH24:MI:SS'),'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(CREATED_BY,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(LAST_UPDATE_LOGIN,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(UNIQUENESS,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(DEPLOY_TO,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(STATUS,'[[:cntrl:]||]',' ' ) ||'|'|| regexp_replace(SHORT_NAME,'[[:cntrl:]||]',' ' )AS TABLE_EXTRACT  FROM FND_INDEXES"""        # elif table == 'FND_SOURCE':        #     self.sql = "SELECT OWNER, NAME, TYPE, LINE, TEXT, ORIGIN_CON_ID FROM FND_SOURCE WHERE OWNER LIKE 'FUSION'"        else:            qry = """SELECT CASE fc.column_type WHEN 'D' THEN 'TO_CHAR(' || fc.column_name || ', ' || '''' || 'DD/MM/YYYY HH24:MI:SS' || '''' || ')' WHEN 'TIMESTAMP' THEN 'TO_CHAR(' || fc.column_name || ', ' || '''' || 'DD/MM/YYYY HH24:MI:SS' || '''' || ')' WHEN 'TIMESTAMP_WITH_TIMEZONE' THEN 'TO_CHAR(' || fc.column_name || ', ' || '''' || 'DD/MM/YYYY HH24:MI:SS' || '''' || ')' WHEN 'CHAR' THEN 'regexp_replace(' || fc.column_name || ',''[[:cntrl:]||]'','' '')' WHEN 'V' THEN 'regexp_replace(' || fc.column_name || ',''[[:cntrl:]||]'','' '')' ELSE fc.column_name END AS cname FROM fnd_tables ft JOIN fnd_columns fc ON ft.table_id = fc.table_id AND fc.column_name NOT LIKE 'EXTN_ATTRIBUTE%' AND fc.status = 'Active' AND fc.column_type IN( 'CHAR', 'D', 'N', 'TIMESTAMP', 'TIMESTAMP_WITH_TIMEZONE', 'V' ) WHERE ft.table_name = '{0}' ORDER BY fc.column_sequence""".format(table)            # logger.debug('{0}: Query issued to generate SQL: {1}'.format(table,qry))            try:                # Run above query to DB to get final select SQL                qry_result = self.run(qry).fetchall()                if qry_result:                    self.sql = 'SELECT '+" ||'|'|| ".join([row[0] for row in qry_result])+ ' AS TABLE_EXTRACT  FROM {0}'.format(table)            except (Exception, WebFault, cx_Oracle.DatabaseError) as e:                error, = e.args                logger.error(error)                self.sql = ''        if self.sql:            logger.debug('Select sql for ' + table + ': ' + self.sql)        else:            logger.warning('{0}: Select SQL preparation failed as table not found in Metadata.'.format(table))        return (self.sql)    def get_insert_sql(self, table):        result = False        try:            if table == 'FND_TABLES':                num_cols = 31            elif table == 'FND_COLUMNS':                num_cols = 25            elif table == 'FND_VIEWS':                num_cols = 16            elif table == 'FND_INDEXES':                num_cols = 12            elif table == 'FND_SOURCE':                num_cols = 6            else:                num_cols = int(self.run("SELECT COUNT(*) FROM fnd_tables ft JOIN fnd_columns fc ON fc.table_id = ft.table_id WHERE fc.column_name NOT LIKE 'EXTN_ATTRIBUTE%' AND fc.status = 'Active' AND fc.column_type IN( 'CHAR', 'D', 'N', 'TIMESTAMP', 'TIMESTAMP_WITH_TIMEZONE', 'V') "                                         "AND table_name = '{0}'".format(table)).fetchall()[0][0])            # logger.debug('Load Table columns {0}'.format(num_cols))            result = 'INSERT INTO {0} VALUES(:'.format(table) + ', :'.join([str(r) for r in range(1, num_cols + 1)]) + ')'            logger.debug('{0}: {1}'.format(table, result))        except cx_Oracle.DatabaseError as e:            error, = e.args            logger.error('{0}: Fail to load table: {1}'.format(table, error.message))        finally:            return result    def load_table(self, table, data):        """Load table with data passed in cp1252 bytes and 64bit encoding.        Usage: load_table(String table, String data)"""        result = False        logger.debug('{0}: Data load started.'.format(table))        try:            # Exit if table can't be truncated to avoid duplicates in table.            if not self.create_table(table):                raise Exception()            # Check if data is received from Cloud            if data is not None:                row_count = len(data)                sql = self.get_insert_sql(table)                if not sql:                    raise Exception()                self.db_con.cursor().execute("ALTER SESSION SET NLS_DATE_FORMAT = 'DD/MM/YYYY HH24:MI:SS'")                for i in range(0, row_count, self.batch_size):                    j = i + self.batch_size if i + self.batch_size < row_count else row_count                    self.db_con.cursor().executemany(sql, data[i:j])                    logger.debug('{0}: {1} rows loaded.'.format(table, j))                # self.db_con.cursor().executemany(sql, data)                self.db_con.commit()                self.run("ALTER SESSION SET NLS_DATE_FORMAT = 'DD/MM/YY'")                logger.info('{0}: Total {1} rows loaded.'.format(table, row_count))            else:                logger.info('{0}: Empty Table.'.format(table))            result = True        except (MemoryError, AttributeError, TypeError, cx_Oracle.DatabaseError) as e:            error, = e.args            logger.error('{0}: Fail to load table: {1}'.format(table, error.message))        except Exception as e:            logger.error('{0}: Fail to load table: {1}'.format(table, e))        finally:            # logger.debug('Exit form load_table()')            return (result)class Bip:    """Class having BIP connection and methods to create data model, schedule report, etc., """    user = None    session = None    sec_serv = None    cat_serv = None    sch_serv = None    rep_serv = None    sec_client = None    cat_client = None    sch_client = None    rep_client = None    xml_file = 'table.xml'    meta_ext_tables = ['FND_VIEWS', 'FND_SOURCE']    def __init__(self, config):        try:            # Get proxy settings            proxy_conf = dict()            if config['FUCLONE'].get('proxy_http'):                proxy_conf['http']=config['FUCLONE'].get('proxy_http')            if config['FUCLONE'].get('proxy_https'):                proxy_conf['https']=config['FUCLONE'].get('proxy_https')            self.url = config[list(config)[1]].get('url')            self.user = config[list(config)[1]].get('user').lower()            password = config[list(config)[1]].get('password')            if (proxy_conf):                self.sec_client = Client(self.url + '/xmlpserver/services/v2/SecurityService?wsdl', proxy=proxy_conf)                self.cat_client = Client(self.url + '/xmlpserver/services/v2/CatalogService?wsdl', proxy=proxy_conf)                self.sch_client = Client(self.url + '/xmlpserver/services/v2/ScheduleService?wsdl', proxy=proxy_conf, plugins=[DeleteEmptyTags()])                self.rep_client = Client(self.url + '/xmlpserver/services/v2/ReportService?wsdl', proxy=proxy_conf, plugins=[DeleteEmptyTags()])            else:                self.sec_client = Client(self.url + '/xmlpserver/services/v2/SecurityService?wsdl')                self.cat_client = Client(self.url + '/xmlpserver/services/v2/CatalogService?wsdl')                self.sch_client = Client(self.url + '/xmlpserver/services/v2/ScheduleService?wsdl', plugins=[DeleteEmptyTags()])                self.rep_client = Client(self.url + '/xmlpserver/services/v2/ReportService?wsdl', plugins=[DeleteEmptyTags()])            self.sec_serv = self.sec_client.service['SecurityService']            self.session = self.sec_serv.login(self.user, password)            self.cat_serv = self.cat_client.service['CatalogService']            self.sch_serv = self.sch_client.service['ScheduleService']            self.rep_serv = self.rep_client.service['ReportService']            logger.debug('Cloud Connection established.')        except WebFault as e:            if 'AccessDeniedException' in e.fault.faultstring:                logger.error('Fusion Authentication Error. Check ini file.')            else:                logger.error('Cloud Connection failed: {0}'.format(e.fault.faultstring))            # os._exit(1)        except Exception as e:            if e:                logger.error('Cloud Connection failed: {0}'.format(e))    def __close__(self):        try:            cloud_db.sec_serv.logout(bipSessionToken=self.session)        except:            pass    def create_folder(self):        """ Create Fuclone folder if not exists and Ture or False            Usage: create_folder()"""        result = False        try:            # delete folder if exists            if self.cat_serv.objectExistInSession(reportObjectAbsolutePath='/~{0}/Fuclone'.format(self.user), bipSessionToken=self.session):               self.cat_serv.deleteObjectInSession(objectAbsolutePath='/~{0}/Fuclone'.format(self.user), bipSessionToken=self.session)            self.cat_serv.createFolderInSession(folderAbsolutePath='/~{0}/Fuclone'.format(self.user), bipSessionToken=self.session)            result = True            logger.debug('Metadata: Fuclone folder created.')        except WebFault as e:            logger.error('Metadata: Fail to create Fuclone folder:'.format(e.fault.faultstring))        except Exception as e:            if e:                logger.error('Metadata: Fail to create Fuclone folder:'.format(e))        finally:            return result    def create_dm(self, table, sql='', filter=''):        """Create Data model with given SQL and create/update on cloud and returns True if success otherwise False.        Usage: create_dm(String table, String sql='', String filter='')"""        dm_update = False        # Prepare data model        if table == "FND_VIEWS":            dm_xml = """<?xml version = '1.0' encoding = 'utf-8'?><dataModel xmlns="http://xmlns.oracle.com/oxp/xmlp" version="2.0" xmlns:xdm="http://xmlns.oracle.com/oxp/xmlp" xmlns:xsd="http://wwww.w3.org/2001/XMLSchema" defaultDataSourceRef="ApplicationDB_FSCM"><description><![CDATA[Extract%20Data%20from%20Fusion%20Cloud]]></description><dataProperties><property name="include_parameters" value="false"/><property name="include_null_Element" value="true"/><property name="include_rowsettag" value="false"/><property name="xml_tag_case" value="upper"/><property name="generate_output_format" value="xml"/><property name="sql_query_timeout" value="10000"/><property name="multithread_query_executions" value="true"/><property name="optimize_query_executions" value="true"/></dataProperties><dataSets><dataSet name="EXTRACT" type="complex"><sql><![CDATA[SELECT view_id AS view_id, view_name AS view_name, application_short_name AS application_short_name, TO_CHAR(last_update_date,'DD/MM/YYYY HH24:MI:SS') AS last_update_date, last_updated_by AS last_updated_by, TO_CHAR(creation_date,'DD/MM/YYYY HH24:MI:SS') AS creation_date, created_by AS created_by, last_update_login AS last_update_login, description AS description, text AS text, status AS status, select_allowed AS select_allowed, insert_allowed AS insert_allowed, update_allowed AS update_allowed, delete_allowed AS delete_allowed, flashback_allowed AS flashback_allowed FROM fnd_views]]></sql></dataSet></dataSets><output rootName="DATA_DS" uniqueRowName="false"><nodeList name="data-structure"><dataStructure tagName="DATA_DS"><group name="G_MAIN" label="G_MAIN" source="EXTRACT"><element name="VIEW_ID" value="VIEW_ID" label="VIEW_ID" dataType="xsd:double" breakOrder="" fieldOrder="1"/><element name="VIEW_NAME" value="VIEW_NAME" label="VIEW_NAME" dataType="xsd:string" breakOrder="" fieldOrder="2"/><element name="APPLICATION_SHORT_NAME" value="APPLICATION_SHORT_NAME" label="APPLICATION_SHORT_NAME" dataType="xsd:string" breakOrder="" fieldOrder="3"/><element name="LAST_UPDATE_DATE" value="LAST_UPDATE_DATE" label="LAST_UPDATE_DATE" dataType="xsd:string" breakOrder="" fieldOrder="4"/><element name="LAST_UPDATED_BY" value="LAST_UPDATED_BY" label="LAST_UPDATED_BY" dataType="xsd:string" breakOrder="" fieldOrder="5"/><element name="CREATION_DATE" value="CREATION_DATE" label="CREATION_DATE" dataType="xsd:string" breakOrder="" fieldOrder="6"/><element name="CREATED_BY" value="CREATED_BY" label="CREATED_BY" dataType="xsd:string" breakOrder="" fieldOrder="7"/><element name="LAST_UPDATE_LOGIN" value="LAST_UPDATE_LOGIN" label="LAST_UPDATE_LOGIN" dataType="xsd:string" breakOrder="" fieldOrder="8"/><element name="DESCRIPTION" value="DESCRIPTION" label="DESCRIPTION" dataType="xsd:string" breakOrder="" fieldOrder="9"/><element name="TEXT" value="TEXT" label="TEXT" dataType="xsd:clob" breakOrder="" fieldOrder="10"/><element name="STATUS" value="STATUS" label="STATUS" dataType="xsd:string" breakOrder="" fieldOrder="11"/><element name="SELECT_ALLOWED" value="SELECT_ALLOWED" label="SELECT_ALLOWED" dataType="xsd:string" breakOrder="" fieldOrder="12"/><element name="INSERT_ALLOWED" value="INSERT_ALLOWED" label="INSERT_ALLOWED" dataType="xsd:string" breakOrder="" fieldOrder="13"/><element name="UPDATE_ALLOWED" value="UPDATE_ALLOWED" label="UPDATE_ALLOWED" dataType="xsd:string" breakOrder="" fieldOrder="14"/><element name="DELETE_ALLOWED" value="DELETE_ALLOWED" label="DELETE_ALLOWED" dataType="xsd:string" breakOrder="" fieldOrder="15"/><element name="FLASHBACK_ALLOWED" value="FLASHBACK_ALLOWED" label="FLASHBACK_ALLOWED" dataType="xsd:string" breakOrder="" fieldOrder="16"/></group></dataStructure></nodeList></output><eventTriggers/><lexicals/><valueSets/><parameters/><bursting/><display><layouts><layout name="EXTRACT" left="321px" top="0px"/><layout name="DATA_DS" left="1px" top="292px"/></layouts><groupLinks/></display></dataModel>"""        elif table == 'FND_SOURCE':            dm_xml = """<?xml version = '1.0' encoding = 'utf-8'?><dataModel xmlns="http://xmlns.oracle.com/oxp/xmlp" version="2.0" xmlns:xdm="http://xmlns.oracle.com/oxp/xmlp" xmlns:xsd="http://wwww.w3.org/2001/XMLSchema" defaultDataSourceRef="ApplicationDB_FSCM"><description><![CDATA[Extract%20Data%20from%20Fusion%20Cloud]]></description><dataProperties><property name="include_parameters" value="false"/><property name="include_null_Element" value="true"/><property name="include_rowsettag" value="false"/><property name="xml_tag_case" value="upper"/><property name="generate_output_format" value="xml"/><property name="sql_query_timeout" value="10000"/><property name="multithread_query_executions" value="true"/><property name="optimize_query_executions" value="true"/></dataProperties><dataSets><dataSet name="EXTRACT" type="complex"><sql><![CDATA[SELECT OWNER, NAME, TYPE, LINE, TEXT, ORIGIN_CON_ID FROM ALL_SOURCE WHERE OWNER ='FUSION' AND TYPE = '{0}' ]]></sql></dataSet></dataSets><output rootName="DATA_DS" uniqueRowName="false"><nodeList name="data-structure"><dataStructure tagName="DATA_DS"><group name="G_MAIN" label="G_MAIN" source="EXTRACT"><element name="OWNER" value="OWNER" label="OWNER" dataType="xsd:string" breakOrder="" fieldOrder="1"/><element name="NAME" value="NAME" label="NAME" dataType="xsd:string" breakOrder="" fieldOrder="2"/><element name="TYPE" value="TYPE" label="TYPE" dataType="xsd:string" breakOrder="" fieldOrder="3"/><element name="LINE" value="LINE" label="LINE" dataType="xsd:double" breakOrder="" fieldOrder="4"/><element name="TEXT" value="TEXT" label="TEXT" dataType="xsd:string" breakOrder="" fieldOrder="5"/><element name="ORIGIN_CON_ID" value="ORIGIN_CON_ID" label="ORIGIN_CON_ID" dataType="xsd:double" breakOrder="" fieldOrder="6"/></group></dataStructure></nodeList></output><eventTriggers/><lexicals/><valueSets/><parameters/><bursting/><display><layouts><layout name="EXTRACT" left="300px" top="292px"/><layout name="DATA_DS" left="6px" top="292px"/></layouts><groupLinks/></display></dataModel>""".format(filter)        else:            dm_xml = """<?xml version = '1.0' encoding = 'utf-8'?>                    <dataModel xmlns="http://xmlns.oracle.com/oxp/xmlp" version="2.0" xmlns:xdm="http://xmlns.oracle.com/oxp/xmlp" xmlns:xsd="http://wwww.w3.org/2001/XMLSchema" defaultDataSourceRef="ApplicationDB_FSCM">                       <description>                          <![CDATA[Extract%20Data%20from%20Fusion%20Cloud]]>                       </description>                       <dataProperties>                          <property name="include_parameters" value="false"/>                          <property name="include_null_Element" value="true"/>                          <property name="include_rowsettag" value="false"/>                          <property name="xml_tag_case" value="upper"/>                          <property name="generate_output_format" value="xml"/>                          <property name="sql_query_timeout" value="10000"/>                          <property name="multithread_query_executions" value="true"/>                          <property name="optimize_query_executions" value="true"/>                       </dataProperties>                       <dataSets>                          <dataSet name="EXTRACT" type="complex">                             <sql>                                <![CDATA[{0}]]>                             </sql>                          </dataSet>                       </dataSets>                       <output rootName="DATA_DS" uniqueRowName="false">                          <nodeList name="data-structure">                             <dataStructure tagName="DATA_DS">                                <group name="G_MAIN" label="G_MAIN" source="EXTRACT">                                   <element name="TABLE_EXTRACT" value="TABLE_EXTRACT" label="TABLE_EXTRACT" dataType="xsd:string" breakOrder="" fieldOrder="1"/>                                </group>                             </dataStructure>                          </nodeList>                       </output>                       <eventTriggers/>                       <lexicals/>                       <valueSets/>                       <parameters/>                       <bursting/>                       <display>                          <layouts>                             <layout name="EXTRACT" left="290px" top="43px"/>                             <layout name="DATA_DS" left="6px" top="292px"/>                          </layouts>                          <groupLinks/>                       </display>                    </dataModel>""".format(sql)        # Update/ Create data model under Fuclone folder        try:            if self.cat_serv.objectExistInSession(reportObjectAbsolutePath='/~{0}/Fuclone/Extract_DM.xdm'.format(self.user), bipSessionToken=self.session):                dm_update = self.cat_serv.updateObjectInSession(objectAbsolutePath='/~{0}/Fuclone/Extract_DM.xdm'.format(self.user), objectData=base64.b64encode(dm_xml.encode('utf-8')).decode("utf-8"), bipSessionToken=self.session)                logger.debug('{0}:Data model Created.'.format(table))            else:                dm_update = self.cat_serv.createObjectInSession(folderAbsolutePathURL='/~{0}/Fuclone/'.format(self.user), objectName='Extract_DM', objectType='xdm', objectData=base64.b64encode(dm_xml.encode('utf-8')).decode("utf-8"), bipSessionToken=self.session)                if dm_update != '/~{0}/Fuclone/Extract_DM.xdm'.format(self.user):                    raise Exception(dm_update)                logger.debug('{0}:Data model Updated.'.format(table))            dm_update = True        except WebFault as e:            dm_update = False            logger.error('{0}: Data model creation failed: {1}'.format(table, e.fault.faultstring))        except Exception as e:            if e:                logger.error('{0}: Data model creation failed: {1}'.format(table, e))        finally:            return dm_update    def create_report(self):        """Uploads Extract_report to Cloud. Returns True if report is created else Fail.        Usage: create_report()"""        result = False        # logger.debug('Report creation started.')        try:            # Create Extract_Report if not exists.            if self.cat_serv.objectExistInSession(reportObjectAbsolutePath='/~{0}/Fuclone/Extract_Report.xdo'.format(self.user), bipSessionToken=self.session):                rep_result = self.cat_serv.deleteObjectInSession(reportObjectAbsolutePath='/~{0}/Fuclone/Extract_Report.xdo'.format(self.user), bipSessionToken=self.session)                if not rep_result:                    raise Exception(rep_result)            with open('Extract_Report.xdoz', 'rb') as f:                rep_result = self.cat_serv.uploadObjectInSession(reportObjectAbsolutePathURL='/~{0}/Fuclone/Extract_Report'.format(self.user), objectType='xdoz', objectZippedData=base64.b64encode(f.read()).decode("utf-8"), bipSessionToken=self.session)            if rep_result == '/~{0}/Fuclone/Extract_Report.xdo'.format(self.user):                dm_result = self.create_dm('FND_TABLES', 'SELECT COUNT(*) AS TABLE_EXTRACT FROM FND_TABLES')                if not dm_result:                    raise Exception(dm_result)                input("Open /~{0}/Fuclone/Extract_Report and link datamodel Extract_DM. Press Enter key when finish...".format(self.user))                result = True                logger.debug('Report creation complete.')            else:                raise Exception(rep_result)        except FileNotFoundError:            logger.error("Metadata: Extract_Report.xdoz file not found.")        except WebFault as e:            logger.error('Metadata: Report creation failed: {0}'.format(e.args[1]))        except Exception as e:            if e:                logger.error('Metadata: Report creation failed: {0}'.format(e))        finally:            return result    def get_counts(self, table):        """Returns row count from table        Usage: get_counts(table)"""        result = False        try:            if table == 'FND_SOURCE':                sql = "SELECT COUNT(*) AS TABLE_EXTRACT FROM ALL_SOURCE WHERE OWNER LIKE 'FUSION'"            else:                sql = 'SELECT COUNT(*) AS TABLE_EXTRACT FROM {0}'.format(table)            if table in self.meta_ext_tables:                result = 1            else:                if cloud_db.create_dm(table, sql):                    rep_req = cloud_db.rep_client.factory.create('ReportRequest')                    rep_req.reportAbsolutePath = '/~{0}/Fuclone/Extract_Report.xdo'.format(cloud_db.user)                    b64data = cloud_db.rep_serv.runReportInSession(reportRequest=rep_req, bipSessionToken=cloud_db.session)                    result = int(base64.b64decode(b64data.reportBytes).decode('cp1252').strip())                    logger.debug('{0}: Row count from cloud {1}.'.format(table, result))                else:                    raise Exception()        except (WebFault, cx_Oracle.DatabaseError, NameError) as e:            error, = e.args            logger.error('{0}: Row count from Cloud failed: {1}'.format(table, error.message))        except Exception as e:            if e:                logger.error('{0}: Row count from Cloud failed: {1}'.format(table, e))        finally:            return result    def create_job(self, table):        """Create a schedule job and returns job id if success else False.         Usage: crete_job(string table_name) """        global clone_db        result = False        try:            if table in self.meta_ext_tables:                result = 1            else:                clone_count = clone_db.get_counts(table)                cloud_count = cloud_db.get_counts(table)                if (clone_count != cloud_count) and (cloud_count > 0):                    # Created data model and submit job                    sql = clone_db.get_sql(table)                    result = self.create_dm(table, sql)                    if result:                        sch_req = self.sch_client.factory.create('ScheduleRequest')                        # sch_req.dataModelUrl = '/~{0}/Fuclone/Extract_DM.xdm'.format(self.user)                        sch_req.userJobName = table + time.strftime(':%I%M')                        sch_req.userJobDesc = table                        sch_req.saveDataOption = True                        sch_req.saveOutputOption = True                        sch_req.reportRequest = self.sch_client.factory.create('ReportRequest')                        sch_req.reportRequest.reportAbsolutePath = '/~{0}/Fuclone/Extract_Report.xdo'.format(self.user)                        sch_req.reportRequest.attributeFormat = 'text'                        sch_req.reportRequest.attributeLocale = 'en-US'                        sch_req.reportRequest.attributeTemplate = 'Output'                        sch_req.reportRequest.byPassCache = True                        sch_req.reportRequest.parameterNameValues = self.sch_client.factory.create('ParamNameValues')                        sch_req.reportRequest.parameterNameValues.listOfParamNameValues = self.sch_client.factory.create('ArrayOfParamNameValue')                        sch_req.startDate = time.strftime("%b %d, %Y %I:%M:%S %p")                        sch_result = self.sch_serv.scheduleReportInSession(scheduleRequest=sch_req, bipSessionToken=self.session)                        # Get jobid                        job_fil = self.sch_client.factory.create('JobFilterProperties')                        job_fil.jobName = sch_req.userJobName                        job_fil.jobNameOperator = 'Equals'                        job_fil.owner = self.user                        job_fil.ownerOperator = 'Equals'                        job_inf = ''                        # Server may be late in creating jobs during busy hours.                        while not job_inf:                            job_inf = self.sch_serv.getAllScheduledReportHistoryInSession(filter=job_fil, beginIdx=1, bipSessionToken=self.session)                            time.sleep(2)                        result = job_inf.jobInfoList.item[0].jobId                        logger.debug('{0}: Extract Job created ({1}, {2})'.format(table, sch_req.userJobName, result))                    else:                        raise Exception(result)                else:                    logger.info('{0}: No change in row count or empty table. Skipping this table.'.format(table))                    result = -1        except WebFault as e:            logger.error('{0}: Extract Job failed to submit: {1}'.format(table, e.fault.faultstring))        except Exception as e:            if e:                logger.error('{0}: Extract Job failed to submit: {1}'.format(table, e))        finally:            return result    def get_job_data(self, table, jobid):        """Returns BIP job data if job is success                              Run if in wait or running state                              Fail for any other status        Usage: get_job_data(String table, Number jobid)"""        data = []        result = 'Fail'        status = ''        meta_dict = {'FND_VIEWS': [''], 'FND_SOURCE': ['FUNCTION', 'PACKAGE', 'PACKAGE BODY', 'PROCEDURE', 'TRIGGER', 'TYPE', 'TYPE BODY']}        try:            if table in self.meta_ext_tables:                for i in range(len(meta_dict[table])):                    logger.debug('{0}:Data model creating with filter {1}'.format(table, meta_dict[table][i]))                    if not self.create_dm(table, '', meta_dict[table][i]):                        raise Exception()                    rep_req = self.rep_client.factory.create('ReportRequest')                    rep_req.reportAbsolutePath = '/~{0}/Fuclone/Extract_DM.xdm'.format(self.user)                    b64data = self.rep_serv.runDataModelInSession(reportRequest=rep_req, bipSessionToken=self.session).reportBytes                    logger.debug('{0}: Extract success. Data size:{1}'.format(table, b64data.__len__()))                    if b64data is not None:                        with open(self.xml_file, 'w') as f:                            f.write(base64.b64decode(b64data).decode('utf-8'))                        # xml_doc = untangle.parse(base64.b64decode(b64data).decode('utf-8'))                        # store to file to solve long path for windows issue                        with open(self.xml_file, 'r') as f:                            xml_doc = untangle.parse(f)                        os.remove(self.xml_file)                        for j in range(xml_doc.DATA_DS.G_MAIN.__len__()):                            line = []                            for l in xml_doc.DATA_DS.G_MAIN[j].__dict__['children'].__iter__():                                line.append(l.__dict__['cdata'])                            if line:                                data.append(line)                        logger.debug('{0}: Row count from Cloud for filter {1}: {2}'.format(table, meta_dict[table][i], len(data)))                result = data                status = 'Success'                logger.debug('{0}: Row count from Cloud {1}'.format(table, len(result)))            else:                status = self.sch_serv.getScheduledJobInfoInSession(jobid, bipSessionToken=self.session).status                logger.debug('{0} extract job status {1}.'.format(table, status))                # Get data in job is success                if status == 'Success':                    doc_id = self.sch_serv.getScheduledReportOutputInfoInSession(jobid, bipSessionToken=self.session).jobOutputList.item[0].outputId                    # logger.debug('get_job: doc_id:{0}.'.format(doc_id))                    # result = self.sch_serv.getDocumentDataInSession(doc_id, bipSessionToken=self.session)                    b64data = self.sch_serv.getDocumentDataInSession(doc_id, bipSessionToken=self.session)                    logger.debug('{0}: Extract success. Data size:{1}'.format(table, b64data.__len__()))                    if b64data is not None:                        data = [line.split('|') for line in base64.b64decode(b64data).decode('cp1252').splitlines()]                    result = data                    logger.debug('{0}: Row count from Cloud {1}'.format(table, len(result)))                elif status in ['Running', 'Waiting']:                    result = 'Run'                else:                    raise Exception(result)        except WebFault as e:            logger.error('{0}: Extract job failed. Check Job {1}({2}):{3} '.format(table, jobid, status, e.fault.faultstring))            # result = 'Fail'        except Exception as e:            if e:                logger.error('{0}: Extract job failed: {1} '.format(table, e))        finally:            return resultdef clone(config, tables):    """Process the tables list in table.txt file, extract from Cloud and load in to Clone database.    Usage: clone(config, tablelist) config: configuration containing connection info,                                        tablelist: Tables list. If empty list is passed, then reads from tables.txt file."""    global clone_db, cloud_db    result = False    pass_list = []    fail_list = []    table_list = []    process_list = {}    logger.debug('Clone process initiated.')    try:        clone_db = Database(config)        if not clone_db.db_con:            raise Exception()        cloud_db = Bip(config)        if not cloud_db.session:            raise Exception()        logger.info('Clone process started.')        if tables:            table_list = tables            logger.info('Tables to process:{0}'.format(', '.join(list(set(table_list)))))        else:            if clone_db.get_tables():                table_list = clone_db.table_list        table_list = list(set(table_list))        if table_list:            logger.info('Jobs being scheduled.')            # Create BIP jobs for FND Tables and add jobid to process list            for table in table_list:                # sql = clone_db.get_sql(table)                job_id = cloud_db.create_job(table)                # logger.debug('{0}: job id:{1}'.format(table,job_id))                if job_id < 0:                    pass_list.append(table)                elif job_id:                    process_list[table] = job_id                else:                    raise Exception(job_id)            logger.debug('Jobs list: {0}'.format(process_list))            # Extract BIP jobs  & load tables            if process_list:                logger.info('BIP jobs submitted to Cloud. Loading process will start once the jobs complete.')            while True:                table = None                for table in list(process_list.keys()):                    data = cloud_db.get_job_data(table, process_list[table])                    if data == 'Fail':                        fail_list.append(table)                        del process_list[table]                    elif data == 'Run':                        pass                    else:                        # logger.debug('{0}:  table.'.format(table))                        if clone_db.load_table(table, data):                            pass_list.append(table)                            del process_list[table]                        else:                            fail_list.append(table)                            del process_list[table]                data = None                # Put system to sleep before it starts list again. job gets time run for a very small process list.                if process_list.keys():                    logger.debug('Load process pending for {0}'.format(list(process_list.keys())))                    time.sleep(30 / len(process_list.keys()))                else:                    break        else:            logger.info('Table List is empty.')        result = True        logger.debug('Processing tables complete.')    except (WebFault, cx_Oracle.DatabaseError) as e:        logger.error('Fail to process tables list: {0}'.format(e.fault.faultstring))    except Exception as e:        if e:            logger.error(e)    finally:        # clone_db.db_con.commit()        if clone_db.db_con and cloud_db.session and table_list:            logger.info('\n#######################################\n##   FUCLONE Clone Process Summary   ##\n#######################################\n\nTotal({0}), Success({1}), '                        'Fail({2})'.format(len(table_list), len(pass_list), len(fail_list)))            if fail_list:                logger.info('List of Tables Failed:{0}'.format(', '.join(fail_list)))        return (result)def cleanup():    global clone_db, cloud_db    try:        clone_db.__close__()    except NameError:        pass    except Exception as e:        print(e)    try:        cloud_db.__close__()    except NameError:        pass    except Exception as e:        print(e)    logger.debug('Connections closed and Memory released.')    logger.shutdown()    logger._acquireLock()    logger._handlers.clear()    logging._releaseLock()    print('\nExiting Fuclone Application.')def main():    """Fuclone clones Fusion cloud database to local database."""    env = ''    log_level = 'debug'    tables_list = ''    global logger, config #, db_version    # Receive command-line switches    parser = argparse.ArgumentParser(description="Clone Fusion Cloud Database", formatter_class=RawTextHelpFormatter)    parser.add_argument("--env", "-e", help="fusion cloud environment name", action="store")    parser.add_argument("--log", "-l", help='log level to generate log file. allowed values: warning, error, info, debug', action="store")    parser.add_argument("--tables", "-t", help='table(s) to clone from cloud. use with clone or fileload process options', action="store")    parser.add_argument("--views", "-v", help='view(s) to create. use with views process', action="store")    parser.add_argument("--file", "-f", help='pipe seperated file path. use with fileload option', action="store")    parser.add_argument("--process", "-p", help='allowed values: clone, metadata, setup\nclone: clone tables from cloud. default, if not given\n'                                                'metadata: reloads FND tables from cloud\nsetup: setup local db and loads FND tables'                                                '\ntables: creates fusion tables\nviews: creates fusion views\nfileload: loads table from file., ex: fuclone -p fileload -t TBL -f filepath',                        action="store")    args = parser.parse_args()    if (args.process is not None) and (args.process.upper() not in ['CLONE', 'SETUP', 'METADATA', 'TABLES', 'VIEWS', 'FILELOAD']):        print('Invalid Argument for Process Name. Terminating Fuclone application.')        os._exit(1)    if args.log:        log_level = args.log.upper()    logger = get_logger(log_level)    if args.env:        env = args.env.upper()    config = get_config(env)    if args.process is None:        process = 'CLONE'    else:        process = args.process.upper()    if process == 'SETUP':        setup_clonedb(config)    elif process == 'METADATA':        setup_metadata(config)    elif process == 'TABLES':        if args.tables:            setup_tables(config, args.tables.upper().replace(' ', '').split(','))        else:            setup_tables(config)    elif process == 'VIEWS':        if args.views:            setup_views(config, args.views.upper().replace(' ', '').split(','))        else:            setup_views(config)    elif process == 'FILELOAD':        if not (args.file and args.tables):            print('Table and File name are required arguments.')        else:            load_file_to_table(config, table=args.tables.upper().replace(' ', '').split(',')[0], file=args.file)    else:        if args.tables:            tables_list = list(filter(len, args.tables.upper().replace(' ', '').split(',')))        clone(config, tables_list)    cleanup()if __name__ == "__main__":    main()